// ── SLIDER ────────────────────────────────────────────────────────────────
(function(){
  var root  = document.getElementById('slRoot');
  var track = document.getElementById('slTrack');
  var prev  = document.getElementById('slPrev');
  var next  = document.getElementById('slNext');
  var dotsC = document.getElementById('slDots');
  if(!root||!track||!prev||!next){ return; }

  var GAP   = 20;
  var cards = Array.from(track.querySelectorAll('.sl-card'));
  var N     = cards.length;
  var cur   = 0;
  var SHOW  = 3;
  var MAX   = 0;
  var CW    = 0;
  var MAX_DOTS = 5;

  function perPage(){
    return window.innerWidth >= 900 ? 3 : window.innerWidth >= 600 ? 2 : 1;
  }

  function buildDots(){
    dotsC.innerHTML = '';
    for(var i = 0; i <= MAX; i++){
      (function(idx){
        var d = document.createElement('button');
        d.className = 'sl-dot';
        d.setAttribute('aria-label','Go to portfolio slide '+(idx+1));
        d.setAttribute('type','button');
        d.onclick = function(){ go(idx); resetAuto(); };
        dotsC.appendChild(d);
      })(i);
    }
    updateDots();
  }

  function updateDots(){
    var allDots = Array.from(dotsC.querySelectorAll('.sl-dot'));
    var total = allDots.length;
    // sliding window of MAX_DOTS centered on cur
    var half = Math.floor(MAX_DOTS / 2);
    var start = Math.max(0, Math.min(cur - half, total - MAX_DOTS));
    var end   = Math.min(total - 1, start + MAX_DOTS - 1);
    allDots.forEach(function(d, i){
      d.className = 'sl-dot' + (i === cur ? ' on' : '');
      d.style.display = (i >= start && i <= end) ? '' : 'none';
    });
  }

  function init(){
    SHOW = perPage();
    MAX  = Math.max(0, N - SHOW);
    cur  = Math.min(cur, MAX);
    var rootW = root.offsetWidth;
    CW = SHOW === 1 ? Math.floor(rootW * 0.85) : Math.floor((rootW - GAP*(SHOW-1)) / SHOW);
    cards.forEach(function(c){ c.style.width = CW+'px'; c.style.flex = '0 0 '+CW+'px'; });
    buildDots();
    applyTransform(false);
    updateVisible();
  }

  function applyTransform(animate){
    var rootW = root.offsetWidth;
    var offset = SHOW === 1 ? Math.round((rootW - CW) / 2) : 0;
    var px = cur * (CW + GAP) - offset;
    px = Math.max(0, px);
    track.style.transition = animate ? 'transform .55s cubic-bezier(.22,1,.36,1)' : 'none';
    track.style.transform  = 'translateX(-'+px+'px)';
  }

  function updateVisible(){
    cards.forEach(function(c,j){
      c.classList.toggle('sl-dim', j < cur || j >= cur + SHOW);
    });
  }


  function go(i){
    cur = Math.max(0, Math.min(i, MAX));
    applyTransform(true);
    updateDots();
    updateVisible();
  }

  prev.onclick = function(e){ e.stopPropagation(); go(cur-1); resetAuto(); };
  next.onclick = function(e){ e.stopPropagation(); go(cur+1); resetAuto(); };

  // card clicks
  cards.forEach(function(c){
    var href = c.getAttribute('data-href');
    if(!href || href==='#'){
      c.style.cursor='default';
      var ov=c.querySelector('.sl-ov'); if(ov) ov.style.display='none';
      return;
    }
    c.addEventListener('click', function(e){ if(e.target.closest('a,button')) return; window.open(href,'_blank'); });
  });

  var autoT;
  var autoPaused = false;
  function stopAuto(){ clearInterval(autoT); }
  function resetAuto(){
    stopAuto();
    if(autoPaused) return;
    autoT=setInterval(function(){ go(cur+1 > MAX ? 0 : cur+1); },4000);
  }
  function pauseAuto(){ autoPaused = true; stopAuto(); }
  function resumeAuto(){ autoPaused = false; resetAuto(); }

  root.addEventListener('mouseenter', pauseAuto);
  root.addEventListener('mouseleave', resumeAuto);
  root.addEventListener('focusin', pauseAuto);
  root.addEventListener('focusout', function(e){ if(!root.contains(e.relatedTarget)) resumeAuto(); });
  root.addEventListener('touchstart', pauseAuto, {passive:true});
  root.addEventListener('touchend', function(){ setTimeout(resumeAuto, 1800); }, {passive:true});

  var resizeT;
  window.addEventListener('resize', function(){
    clearTimeout(resizeT);
    resizeT = setTimeout(init, 150);
  });

  init();
  resetAuto();
})();


// Number counter animation
(function(){
  var nums = document.querySelectorAll('.num-val[data-target]');
  var observer = new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(!entry.isIntersecting) return;
      var el = entry.target;
      var target = parseInt(el.getAttribute('data-target'));
      var start = 0;
      var duration = 1800;
      var step = target / (duration / 16);
      var timer = setInterval(function(){
        start = Math.min(start + step, target);
        el.textContent = Math.floor(start);
        if(start >= target){ el.textContent = target; clearInterval(timer); }
      }, 16);
      observer.unobserve(el);
    });
  }, {threshold: 0.5});
  nums.forEach(function(n){ observer.observe(n); });
})();

