// Vimeo testimonials: load Vimeo iframe + SDK only after click/tap.
function loadVimeoSdk(cb){
  if(typeof Vimeo !== "undefined"){ cb && cb(); return; }
  var existing = document.getElementById("vimeo-sdk");
  if(existing){ if(cb) existing.addEventListener("load", cb, {once:true}); return; }
  var s = document.createElement("script");
  s.id = "vimeo-sdk";
  s.src = "https://player.vimeo.com/api/player.js";
  s.async = true;
  if(cb) s.addEventListener("load", cb, {once:true});
  document.head.appendChild(s);
}
function getVimeoAutoplaySrc(src){
  try{
    var url = new URL(src, window.location.origin);
    url.searchParams.set("autoplay", "1");
    url.searchParams.set("playsinline", "1");
    url.searchParams.set("muted", "0");
    return url.toString();
  }catch(err){
    var joiner = src.indexOf("?") === -1 ? "?" : "&";
    return src + joiner + "autoplay=1&playsinline=1&muted=0";
  }
}
function loadVimeoFrame(iframe){
  if(!iframe || iframe.src) return;
  var src = iframe.getAttribute("data-src");
  if(!src) return;
  iframe.src = getVimeoAutoplaySrc(src);
  var wrap = iframe.closest(".vid-wrap");
  if(wrap) wrap.classList.add("is-loaded");
  loadVimeoSdk(initVimeoHover);
}
function setupLazyVimeo(){
  var frames = Array.from(document.querySelectorAll('iframe[data-src*="player.vimeo.com"]'));
  if(!frames.length) return;
  frames.forEach(function(frame){
    var trigger = frame.closest(".vid-wrap") || frame.closest(".vid-card") || frame.parentElement;
    if(!trigger) return;
    trigger.setAttribute("role", "button");
    trigger.setAttribute("tabindex", "0");
    trigger.setAttribute("aria-label", "Play video testimonial");
    function open(e){
      if(e && e.type === "touchend") e.preventDefault();
      loadVimeoFrame(frame);
    }
    trigger.addEventListener("click", open, {once:true});
    trigger.addEventListener("touchend", open, {once:true, passive:false});
    trigger.addEventListener("keydown", function(e){
      if(e.key === "Enter" || e.key === " "){
        e.preventDefault();
        open(e);
      }
    }, {once:true});
  });
}
function initVimeoHover(){
  if(typeof Vimeo === "undefined") return;
  document.querySelectorAll(".vid-card").forEach(function(card){
    if(card.dataset.vimeoBound === "1") return;
    var iframe = card.querySelector("iframe");
    if(!iframe || !iframe.src) return;
    try { new Vimeo.Player(iframe); } catch(e){ return; }
    card.dataset.vimeoBound = "1";
  });
}
setupLazyVimeo();

// ── VIDEO TESTIMONIAL SLIDER ───────────────────────────────────────
(function(){
  var root  = document.getElementById('vslRoot');
  var track = document.getElementById('vslTrack');
  var prev  = document.getElementById('vslPrev');
  var next  = document.getElementById('vslNext');
  var dotsC = document.getElementById('vslDots');
  if(!root||!track||!prev||!next) return;

  var GAP  = 17.6; // 1.1rem @ 16px base
  var cards = Array.from(track.querySelectorAll('.vid-card'));
  var N    = cards.length;
  var cur  = 0;
  var SHOW = 3;
  var MAX  = 0;
  var CW   = 0;

  function vslPerPage(){ return window.innerWidth >= 900 ? 3 : window.innerWidth >= 600 ? 2 : 1; }

  function buildDots(){
    dotsC.innerHTML = '';
    for(var i=0;i<=MAX;i++){
      (function(idx){
        var d=document.createElement('button');
        d.className='vsl-dot'+(idx===0?' on':'');
        d.setAttribute('aria-label','Go to video testimonial slide '+(idx+1));
        d.setAttribute('type','button');
        d.addEventListener('click',function(){ go(idx); });
        dotsC.appendChild(d);
      })(i);
    }
  }

  function updateDots(){
    dotsC.querySelectorAll('.vsl-dot').forEach(function(d,i){
      d.classList.toggle('on',i===cur);
    });
  }

  function init(){
    SHOW = vslPerPage();
    MAX  = Math.max(0, N - SHOW);
    cur  = Math.min(cur, MAX);
    CW   = (root.offsetWidth - GAP*(SHOW-1)) / SHOW;
    cards.forEach(function(c){ c.style.width = CW+'px'; c.style.flex = '0 0 '+CW+'px'; });
    buildDots();
    go(cur);
  }

  function go(n){
    cur=Math.max(0,Math.min(n,MAX));
    track.style.transition='transform .55s cubic-bezier(.22,1,.36,1)';
    track.style.transform='translateX(-'+(cur*(CW+GAP))+'px)';
    prev.disabled=(cur===0);
    next.disabled=(cur===MAX);
    updateDots();
  }

  prev.addEventListener('click',function(){ go(cur-1); });
  next.addEventListener('click',function(){ go(cur+1); });

  var resizeT;
  window.addEventListener('resize', function(){
    clearTimeout(resizeT);
    resizeT = setTimeout(init, 150);
  });

  init();
})();

