  async function run(i){
    var data=QUERIES[i];
    addUser(data.q);
    await wait(420);

    // searching bubble
    var bb=botShell();
    var bub=document.createElement('div');
    bub.className='riq-bub';
    bub.innerHTML='<div class="riq-search-line"><span class="riq-spin"></span>Searching related keywords…</div><div class="riq-kw-wrap"></div>';
    bb.appendChild(bub); scrollDown();
    var wrap=bub.querySelector('.riq-kw-wrap');

    for(var k=0;k<data.kw.length;k++){
      await wait(360);
      var isTop=(k===data.kw.length-1);
      var chip=document.createElement('span');
      chip.className='riq-kw'+(isTop?' top':'');
      chip.style.animationDelay='0s';
      chip.textContent=data.kw[k];
      wrap.appendChild(chip); scrollDown();
    }

    await wait(550);
    // typing indicator
    var tb=botShell();
    var typing=document.createElement('div');
    typing.className='riq-typing';
    typing.innerHTML='<span></span><span></span><span></span>';
    tb.appendChild(typing); scrollDown();
    await wait(950);
    tb.parentNode.removeChild(tb);

    // answer + result card
    var ab=botShell();
    var ansBub=document.createElement('div');
    ansBub.className='riq-bub';
    ansBub.textContent=data.a;
    ab.appendChild(ansBub);

    var result=document.createElement('div');
    result.className='riq-result';
    result.innerHTML='<div class="riq-rank">AI OVERVIEW · #1 RESULT</div>'+
      '<div class="riq-result-top"><div class="riq-result-logo">'+data.bizInit+'</div><div><div class="riq-result-name">'+data.biz+' <span class="riq-stars">★ 4.9</span></div><div class="riq-result-sub">'+data.sub+'</div></div></div>'+
      '<div class="riq-result-cta-note">👆 This spot is taken — by someone else. <a class="riq-result-go" href="/free-audit" style="display:inline-flex;margin-top:.5rem">Make sure it\'s YOUR business next time <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></a></div>';
    ab.appendChild(result); scrollDown();

    // pause on result, then clear and run next
    await wait(3200);
    body.innerHTML='';
    current=(i+1)%QUERIES.length;
    run(current);
  }

  // Start when section scrolls into view
  if('IntersectionObserver' in window){
    var io=new IntersectionObserver(function(entries){
      entries.forEach(function(en){
        if(en.isIntersecting && !started){ started=true; setTimeout(function(){ run(0); },500); io.disconnect(); }
      });
    },{threshold:0.35});
    io.observe(chat);
  }else{ started=true; run(0); }
})();
